// 三载体一致:纯函数,无 DOM/CSS/uplink 足迹;你自己渲染返回的轮廓
import { getStroke } from 'https://cdn.jsdelivr.net/npm/perfect-freehand@1.2.3/+esm';
const outline = getStroke(data.points, data.options ?? {}); // number[][]
// 官方推荐的 quadratic-smooth 拼成 SVG path d:
const d = outline.length ? outline.reduce((acc, [x0, y0], i, a) => { const [x1, y1] = a[(i + 1) % a.length]; acc.push(x0, y0, (x0 + x1) / 2, (y0 + y1) / 2); return acc; }, ['M', ...outline[0], 'Q']).join(' ') + ' Z' : '';
// 把 d 塞进 <path> 或用 new Path2D(d) 填到 canvas(render 由消费 AI 按载体接原生)
